module temperature_shutdown(  
    input wire clk,  
    input wire reset,  
    input wire [7:0] temperature,  
    output reg shutdown  
);  
    parameter THRESHOLD = 8'd80;  
    parameter SAFE_TEMP = 8'd70;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset) begin  
            shutdown <= 1'b0;  
        end else if (temperature > THRESHOLD) begin  
            shutdown <= 1'b1;  
        end else if (temperature < SAFE_TEMP) begin  
            shutdown <= 1'b0;  
        end  
    end  
endmodule
